import{_ as a,c as i,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"AI App Factory: Guía de Mejores Prácticas - Descripción del Producto, Checkpoints, Alcance e Iteración | Tutorial","description":"Domina las mejores prácticas de AI App Factory para mejorar la calidad y eficiencia de las aplicaciones generadas por IA. Aprende a escribir descripciones de productos claras, utilizar checkpoints para controlar la calidad, definir objetivos negativos para evitar el alcance excesivo, validar ideas mediante iteración gradual, ahorrar tokens con sesiones separadas y gestionar fallos y reintentos. Este tutorial cubre seis técnicas: calidad de entrada, confirmación de checkpoints, control de MVP, desarrollo iterativo, optimización de contexto y gestión de fallos.","frontmatter":{"title":"AI App Factory: Guía de Mejores Prácticas - Descripción del Producto, Checkpoints, Alcance e Iteración | Tutorial","sidebarTitle":"Mejores Prácticas","subtitle":"Mejores Prácticas: Descripciones Claras, Uso de Checkpoints, Control de Alcance y Técnicas de Iteración","description":"Domina las mejores prácticas de AI App Factory para mejorar la calidad y eficiencia de las aplicaciones generadas por IA. Aprende a escribir descripciones de productos claras, utilizar checkpoints para controlar la calidad, definir objetivos negativos para evitar el alcance excesivo, validar ideas mediante iteración gradual, ahorrar tokens con sesiones separadas y gestionar fallos y reintentos. Este tutorial cubre seis técnicas: calidad de entrada, confirmación de checkpoints, control de MVP, desarrollo iterativo, optimización de contexto y gestión de fallos.","tags":["Mejores Prácticas","MVP","Desarrollo Iterativo"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":200},"headers":[],"relativePath":"es/hyz1992/agent-app-factory/faq/best-practices/index.md","filePath":"es/hyz1992/agent-app-factory/faq/best-practices/index.md"}'),t={name:"es/hyz1992/agent-app-factory/faq/best-practices/index.md"};function s(n,e,l,c,d,p){return o(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="mejores-practicas-descripciones-claras-uso-de-checkpoints-control-de-alcance-y-tecnicas-de-iteracion" tabindex="-1">Mejores Prácticas: Descripciones Claras, Uso de Checkpoints, Control de Alcance y Técnicas de Iteración <a class="header-anchor" href="#mejores-practicas-descripciones-claras-uso-de-checkpoints-control-de-alcance-y-tecnicas-de-iteracion" aria-label="Permalink to &quot;Mejores Prácticas: Descripciones Claras, Uso de Checkpoints, Control de Alcance y Técnicas de Iteración&quot;">​</a></h1><h2 id="que-podras-hacer-despues-de-este-curso" tabindex="-1">Qué Podrás Hacer Después de Este Curso <a class="header-anchor" href="#que-podras-hacer-despues-de-este-curso" aria-label="Permalink to &quot;Qué Podrás Hacer Después de Este Curso&quot;">​</a></h2><p>Al completar este curso, dominarás:</p><ul><li>Cómo escribir descripciones de productos de alta calidad para que la IA entienda tus ideas</li><li>Cómo utilizar el mecanismo de checkpoints para controlar la calidad de salida de cada etapa</li><li>Cómo establecer límites de alcance mediante objetivos negativos para evitar la expansión del proyecto</li><li>Cómo validar ideas rápidamente mediante iteración gradual y optimización continua</li></ul><h2 id="tu-dilema-actual" tabindex="-1">Tu Dilema Actual <a class="header-anchor" href="#tu-dilema-actual" aria-label="Permalink to &quot;Tu Dilema Actual&quot;">​</a></h2><p>¿Te encuentras en alguna de estas situaciones?</p><ul><li>&quot;Lo expliqué muy claramente, ¿por qué lo generado no es lo que quería?&quot;</li><li>&quot;Un detalle incorrecto hace que todo lo demás esté mal, corregirlo es muy doloroso&quot;</li><li>&quot;Durante el desarrollo, las funciones se acumulan y es imposible finalizar&quot;</li><li>&quot;Quise hacer todas las funciones a la vez, pero al final no hice nada&quot;</li></ul><h2 id="cuando-utilizar-estas-tecnicas" tabindex="-1">Cuándo Utilizar Estas Técnicas <a class="header-anchor" href="#cuando-utilizar-estas-tecnicas" aria-label="Permalink to &quot;Cuándo Utilizar Estas Técnicas&quot;">​</a></h2><p>Ya sea que sea tu primera vez usando AI App Factory o que ya tengas experiencia, estas mejores prácticas te ayudarán a:</p><ul><li><strong>Mejorar la calidad de salida</strong>: que las aplicaciones generadas cumplan con tus expectativas</li><li><strong>Ahorrar tiempo de modificación</strong>: evitar la acumulación de errores, detectar problemas temprano</li><li><strong>Controlar el tamaño del proyecto</strong>: enfocarse en el MVP y entregar rápidamente</li><li><strong>Reducir los costos de desarrollo</strong>: validar por etapas para evitar inversiones ineficaces</li></ul><h2 id="🎒-preparativos-previos" tabindex="-1">🎒 Preparativos Previos <a class="header-anchor" href="#🎒-preparativos-previos" aria-label="Permalink to &quot;🎒 Preparativos Previos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Requisitos Previos</p><ul><li>Lee la <a href="./../../start/getting-started/">Introducción Rápida</a> para entender los conceptos básicos de AI App Factory</li><li>Lee la <a href="./../../start/pipeline-overview/">Visión General de la Línea de 7 Etapas</a> para comprender el proceso completo</li><li>Has completado al menos una ejecución completa de la línea (para tener una percepción intuitiva de la salida de cada etapa)</li></ul></div><h2 id="ideas-clave" tabindex="-1">Ideas Clave <a class="header-anchor" href="#ideas-clave" aria-label="Permalink to &quot;Ideas Clave&quot;">​</a></h2><p>Las mejores prácticas de AI App Factory giran en torno a cuatro principios fundamentales:</p><ol><li><strong>La calidad de entrada determina la calidad de salida</strong>: una descripción de producto clara y detallada es el primer paso para el éxito</li><li><strong>Los checkpoints son líneas de defensa de calidad</strong>: confirma cuidadosamente después de cada etapa para evitar la acumulación de errores</li><li><strong>Enfoque MVP</strong>: define objetivos negativos, controla el alcance y entrega rápidamente las funciones principales</li><li><strong>Iteración continua</strong>: valida primero la idea central y luego expande las funciones gradualmente</li></ol><p>Estos principios provienen de la síntesis del código fuente y la experiencia práctica; seguirlos puede multiplicar tu eficiencia de desarrollo por varias veces.</p><h2 id="sigue-los-pasos" tabindex="-1">Sigue los Pasos <a class="header-anchor" href="#sigue-los-pasos" aria-label="Permalink to &quot;Sigue los Pasos&quot;">​</a></h2><h3 id="tecnica-1-proporcionar-una-descripcion-clara-del-producto" tabindex="-1">Técnica 1: Proporcionar una Descripción Clara del Producto <a class="header-anchor" href="#tecnica-1-proporcionar-una-descripcion-clara-del-producto" aria-label="Permalink to &quot;Técnica 1: Proporcionar una Descripción Clara del Producto&quot;">​</a></h3><h4 id="por-que" tabindex="-1">Por Qué <a class="header-anchor" href="#por-que" aria-label="Permalink to &quot;Por Qué&quot;">​</a></h4><p>Cuando la IA entiende tu idea, solo puede depender de la información textual que proporcionas. Cuanto más clara sea la descripción, más se ajustará el resultado generado a tus expectativas.</p><h4 id="como-hacerlo" tabindex="-1">Cómo Hacerlo <a class="header-anchor" href="#como-hacerlo" aria-label="Permalink to &quot;Cómo Hacerlo&quot;">​</a></h4><p><strong>Una buena descripción de producto incluye los siguientes elementos</strong>:</p><ul><li><strong>Usuarios objetivo</strong>: ¿quién usará este producto?</li><li><strong>Problema central</strong>: ¿qué dificultades enfrentan los usuarios?</li><li><strong>Solución</strong>: ¿cómo resuelve el producto esta dificultad?</li><li><strong>Funciones clave</strong>: ¿qué funciones deben incluirse?</li><li><strong>Escenarios de uso</strong>: ¿en qué situaciones lo usarán los usuarios?</li><li><strong>Condiciones de restricción</strong>: ¿qué limitaciones o requisitos especiales hay?</li></ul><h4 id="ejemplos-comparativos" tabindex="-1">Ejemplos Comparativos <a class="header-anchor" href="#ejemplos-comparativos" aria-label="Permalink to &quot;Ejemplos Comparativos&quot;">​</a></h4><table tabindex="0"><thead><tr><th>❌ Mala Descripción</th><th>✅ Buena Descripción</th></tr></thead><tbody><tr><td>Haz una app de fitness</td><td>Aplicación para ayudar a principiantes en fitness a registrar entrenamientos, admite registro de tipo de ejercicio, duración, calorías quemadas y visualización de estadísticas de entrenamiento semanal. Los usuarios objetivo son jóvenes que comienzan en fitness, las funciones principales son registro rápido y visualización del progreso, no incluye compartir en redes sociales ni funciones de pago</td></tr><tr><td>Haz una app de contabilidad</td><td>Aplicación móvil de contabilidad para ayudar a jóvenes a registrar gastos diarios, las funciones principales son registrar importe, seleccionar categoría (alimentación, transporte, entretenimiento, otros), ver gasto total del mes y estadísticas por categoría. Admite uso sin conexión, los datos se guardan solo localmente</td></tr><tr><td>Haz una herramienta de gestión de tareas</td><td>Herramienta simple para ayudar a equipos pequeños a gestionar tareas, admite crear tareas, asignar miembros, establecer fechas de vencimiento y ver lista de tareas. Los miembros del equipo pueden compartir el estado de tareas. No necesita flujos de trabajo complejos ni gestión de permisos</td></tr></tbody></table><h4 id="checklist-de-verificacion-✅" tabindex="-1">Checklist de Verificación ✅ <a class="header-anchor" href="#checklist-de-verificacion-✅" aria-label="Permalink to &quot;Checklist de Verificación ✅&quot;">​</a></h4><ul><li>[ ] La descripción identifica claramente a los usuarios objetivo</li><li>[ ] La descripción explica el problema central que enfrentan los usuarios</li><li>[ ] La descripción enumera las funciones clave (no más de 5)</li><li>[ ] La descripción incluye condiciones de restricción u objetivos negativos</li></ul><hr><h3 id="tecnica-2-confirmar-cuidadosamente-en-los-checkpoints" tabindex="-1">Técnica 2: Confirmar Cuidadosamente en los Checkpoints <a class="header-anchor" href="#tecnica-2-confirmar-cuidadosamente-en-los-checkpoints" aria-label="Permalink to &quot;Técnica 2: Confirmar Cuidadosamente en los Checkpoints&quot;">​</a></h3><h4 id="por-que-1" tabindex="-1">Por Qué <a class="header-anchor" href="#por-que-1" aria-label="Permalink to &quot;Por Qué&quot;">​</a></h4><p>Después de cada etapa de la línea, se pausa en un checkpoint esperando tu confirmación. Esta es una <strong>línea de defensa de calidad</strong> que te permite detectar problemas temprano y evitar que los errores se propaguen a etapas posteriores.</p><p>Si detectas un problema en esta etapa, solo necesitas volver a ejecutar la etapa actual; si esperas hasta el final para descubrirlo, es posible que necesites revertir múltiples etapas, desperdiciando mucho tiempo y tokens.</p><h4 id="como-hacerlo-1" tabindex="-1">Cómo Hacerlo <a class="header-anchor" href="#como-hacerlo-1" aria-label="Permalink to &quot;Cómo Hacerlo&quot;">​</a></h4><p><strong>Al confirmar cada checkpoint, verifica lo siguiente</strong>:</p><p><strong>Checkpoint de Bootstrap</strong>:</p><ul><li>[ ] La definición del problema en <code>input/idea.md</code> es precisa</li><li>[ ] El perfil de usuarios objetivo es claro y específico</li><li>[ ] La propuesta de valor central es clara</li><li>[ ] Las condiciones de suposición son razonables</li></ul><p><strong>Checkpoint de PRD</strong>:</p><ul><li>[ ] Las historias de usuario son claras e incluyen criterios de aceptación</li><li>[ ] La lista de funciones no supera las 7 (principio MVP)</li><li>[ ] Se enumeran claramente los objetivos negativos (Non-Goals)</li><li>[ ] No contiene detalles técnicos (como React, API, base de datos)</li></ul><p><strong>Checkpoint de UI</strong>:</p><ul><li>[ ] La estructura de páginas es razonable, no más de 3 páginas</li><li>[ ] Se puede previsualizar el prototipo en el navegador</li><li>[ ] El flujo de interacción es claro</li><li>[ ] El estilo estético es distintivo (evitar el estilo común de IA)</li></ul><p><strong>Checkpoint de Tech</strong>:</p><ul><li>[ ] La selección del stack tecnológico es razonable y cumple el principio MVP</li><li>[ ] El diseño del modelo de datos es simple, no más de 10 tablas</li><li>[ ] La lista de endpoints API está completa</li><li>[ ] No introduce microservicios, caché u otros diseños excesivos</li></ul><p><strong>Checkpoint de Code</strong>:</p><ul><li>[ ] La estructura del código frontend y backend está completa</li><li>[ ] Incluye casos de prueba</li><li>[ ] No hay tipos <code>any</code> obvios</li><li>[ ] Incluye README.md explicando cómo ejecutar</li></ul><p><strong>Checkpoint de Validation</strong>:</p><ul><li>[ ] El informe de validación no tiene problemas graves de seguridad</li><li>[ ] Cobertura de pruebas &gt; 60%</li><li>[ ] La instalación de dependencias no tiene conflictos</li><li>[ ] La verificación de tipos TypeScript pasa</li></ul><p><strong>Checkpoint de Preview</strong>:</p><ul><li>[ ] README.md incluye instrucciones completas de ejecución</li><li>[ ] La configuración Docker puede construirse normalmente</li><li>[ ] Se pueden iniciar los servicios frontend y backend localmente</li><li>[ ] Incluye instrucciones de configuración de variables de entorno</li></ul><h4 id="flujo-de-confirmacion-de-checkpoint" tabindex="-1">Flujo de Confirmación de Checkpoint <a class="header-anchor" href="#flujo-de-confirmacion-de-checkpoint" aria-label="Permalink to &quot;Flujo de Confirmación de Checkpoint&quot;">​</a></h4><p>En cada checkpoint, el sistema proporcionará las siguientes opciones:</p><ul><li><strong>Continuar</strong>: si la salida cumple con las expectativas, continuar a la siguiente etapa</li><li><strong>Reintentar</strong>: si la salida tiene problemas, proporcionar sugerencias de modificación y volver a ejecutar la etapa actual</li><li><strong>Pausar</strong>: si necesitas más información o quieres ajustar la idea, pausar la línea</li></ul><p><strong>Principios de decisión</strong>:</p><ul><li>✅ <strong>Continuar</strong>: todos los elementos de verificación cumplen los requisitos</li><li>⚠️ <strong>Reintentar</strong>: problemas menores (formato, omisiones, detalles) que pueden corregirse inmediatamente</li><li>🛑 <strong>Pausar</strong>: problemas graves (dirección incorrecta, alcance descontrolado, no corregibles) que requieren replanificación</li></ul><h4 id="advertencia-de-errores-comunes" tabindex="-1">Advertencia de Errores Comunes <a class="header-anchor" href="#advertencia-de-errores-comunes" aria-label="Permalink to &quot;Advertencia de Errores Comunes&quot;">​</a></h4><div class="danger custom-block"><p class="custom-block-title">Error Común</p><p><strong>¡No saltes la confirmación de checkpoints para &quot;terminar rápido&quot;!</strong></p><p>La línea está diseñada como &quot;pausar y confirmar en cada etapa&quot; precisamente para que detectes problemas a tiempo. Si acostumbras hacer clic en &quot;continuar&quot; y descubres el problema al final, es posible que necesites:</p><ul><li>Revertir múltiples etapas</li><li>Reejecutar mucho trabajo</li><li>Desperdiciar muchos tokens</li></ul><p>Recuerda: <strong>el tiempo invertido en confirmar checkpoints es mucho menor que el costo de revertir y rehacer</strong>.</p></div><hr><h3 id="tecnica-3-utilizar-objetivos-negativos-para-controlar-el-alcance" tabindex="-1">Técnica 3: Utilizar Objetivos Negativos para Controlar el Alcance <a class="header-anchor" href="#tecnica-3-utilizar-objetivos-negativos-para-controlar-el-alcance" aria-label="Permalink to &quot;Técnica 3: Utilizar Objetivos Negativos para Controlar el Alcance&quot;">​</a></h3><h4 id="por-que-2" tabindex="-1">Por Qué <a class="header-anchor" href="#por-que-2" aria-label="Permalink to &quot;Por Qué&quot;">​</a></h4><p><strong>Los objetivos negativos (Non-Goals) son el arma central del desarrollo MVP</strong>. Enumerar claramente &quot;qué no hacer&quot; puede prevenir eficazmente la expansión del alcance.</p><p>Muchos proyectos fallan no por tener pocas funciones, sino por tener demasiadas. Cada nueva función aumenta la complejidad, el tiempo de desarrollo y los costos de mantenimiento. Establecer límites claros y enfocarse en el valor central permite entregar rápidamente.</p><h4 id="como-hacerlo-2" tabindex="-1">Cómo Hacerlo <a class="header-anchor" href="#como-hacerlo-2" aria-label="Permalink to &quot;Cómo Hacerlo&quot;">​</a></h4><p><strong>En la etapa Bootstrap, enumera claramente los objetivos negativos</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Objetivos Negativos (Funciones no incluidas en esta versión)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No admite colaboración multiusuario</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No admite sincronización en tiempo real</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No admite integración con servicios de terceros (como pagos, mapas)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No proporciona funciones de análisis de datos o reportes</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">5.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No incluye funciones para compartir en redes sociales</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">6.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No requiere autenticación de usuario o funciones de inicio de sesión</span></span></code></pre></div><p><strong>En la etapa PRD, incluye los objetivos negativos como sección independiente</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Objetivos Negativos (Definitivamente no incluidos en esta versión)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Las siguientes funciones tienen valor, pero no están dentro del alcance de este MVP:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Función | Razón | Plan Futuro |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| --- | --- | --- |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Colaboración multiusuario | Enfocado en usuarios individuales | Considerar en v2.0 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Sincronización en tiempo real | Aumenta complejidad técnica | Considerar si hay fuerte feedback de usuarios |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Integración de pagos | No es valor central | Considerar en v1.5 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Análisis de datos | MVP no lo necesita | Considerar en v2.0 |</span></span></code></pre></div><h4 id="criterios-para-determinar-objetivos-negativos" tabindex="-1">Criterios para Determinar Objetivos Negativos <a class="header-anchor" href="#criterios-para-determinar-objetivos-negativos" aria-label="Permalink to &quot;Criterios para Determinar Objetivos Negativos&quot;">​</a></h4><p><strong>Cómo determinar si algo debe ser un objetivo negativo</strong>:</p><ul><li>❌ Esta función no es necesaria para validar la idea central → como objetivo negativo</li><li>❌ Esta función aumenta significativamente la complejidad técnica → como objetivo negativo</li><li>❌ Esta función puede sustituirse manualmente → como objetivo negativo</li><li>✅ Esta función es la razón de ser del producto → debe incluirse</li></ul><h4 id="advertencia-de-trampa-de-expansion-de-alcance" tabindex="-1">Advertencia de Trampa de Expansión de Alcance <a class="header-anchor" href="#advertencia-de-trampa-de-expansion-de-alcance" aria-label="Permalink to &quot;Advertencia de Trampa de Expansión de Alcance&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Trampa de Expansión de Alcance</p><p><strong>Señales comunes de expansión de alcance</strong>:</p><ol><li>&quot;Es muy simple, agregue uno más de paso...&quot;</li><li>&quot;Los competidores tienen esta función, nosotros también...&quot;</li><li>&quot;Los usuarios podrían necesitarlo, mejor hacerlo primero...&quot;</li><li>&quot;Esta función es interesante, puede mejorar el punto destacado del producto...&quot;</li></ol><p><strong>Cuando te encuentres con estas ideas, pregúntate tres cosas</strong>:</p><ol><li>¿Esta función ayuda a validar la idea central?</li><li>¿Sin esta función, el producto sigue siendo utilizable?</li><li>¿Agregar esta función retrasará el tiempo de entrega?</li></ol><p>Si la respuesta es &quot;no necesario&quot;, &quot;sí puede usarse&quot;, &quot;retrasará&quot;, entonces clasifícalo como objetivo negativo.</p></div><hr><h3 id="tecnica-4-iterar-gradualmente-validar-rapidamente" tabindex="-1">Técnica 4: Iterar Gradualmente, Validar Rápidamente <a class="header-anchor" href="#tecnica-4-iterar-gradualmente-validar-rapidamente" aria-label="Permalink to &quot;Técnica 4: Iterar Gradualmente, Validar Rápidamente&quot;">​</a></h3><h4 id="por-que-3" tabindex="-1">Por Qué <a class="header-anchor" href="#por-que-3" aria-label="Permalink to &quot;Por Qué&quot;">​</a></h4><p><strong>La idea central del MVP (Producto Mínimo Viable) es validar ideas rápidamente</strong>, no hacerlo perfecto de una sola vez.</p><p>Mediante el desarrollo iterativo, puedes:</p><ul><li>Obtener feedback de usuarios temprano</li><li>Ajustar el dirección a tiempo</li><li>Reducir los costos hundidos</li><li>Mantener el impulso de desarrollo</li></ul><h4 id="como-hacerlo-3" tabindex="-1">Cómo Hacerlo <a class="header-anchor" href="#como-hacerlo-3" aria-label="Permalink to &quot;Cómo Hacerlo&quot;">​</a></h4><p><strong>Pasos del desarrollo iterativo</strong>:</p><p><strong>Primera ronda: Validación de funciones centrales</strong></p><ol><li>Usa AI App Factory para generar la primera versión de la aplicación</li><li>Incluye solo las 3-5 funciones principales</li><li>Ejecuta y prueba rápidamente</li><li>Muestra el prototipo a usuarios reales y recopila feedback</li></ol><p><strong>Segunda ronda: Optimización basada en feedback</strong></p><ol><li>Según el feedback de usuarios, determina los puntos de mejora de mayor prioridad</li><li>Modifica <code>input/idea.md</code> o <code>artifacts/prd/prd.md</code></li><li>Usa <code>factory run &lt;stage&gt;</code> para reejecutar desde la etapa correspondiente</li><li>Genera nueva versión y prueba</li></ol><p><strong>Tercera ronda: Expansión de funciones</strong></p><ol><li>Evalúa si se han alcanzado los objetivos centrales</li><li>Selecciona 2-3 funciones de alto valor</li><li>Genera e integra a través de la línea</li><li>Itera continuamente, mejora gradualmente</li></ol><h4 id="ejemplo-practico-de-iteracion" tabindex="-1">Ejemplo Práctico de Iteración <a class="header-anchor" href="#ejemplo-practico-de-iteracion" aria-label="Permalink to &quot;Ejemplo Práctico de Iteración&quot;">​</a></h4><p><strong>Escenario</strong>: quieres hacer una aplicación de gestión de tareas</p><p><strong>Primera ronda MVP</strong>:</p><ul><li>Funciones centrales: crear tarea, ver lista, marcar completada</li><li>Objetivos negativos: gestión de miembros, control de permisos, notificaciones de recordatorio</li><li>Tiempo de entrega: 1 día</li></ul><p><strong>Segunda ronda optimización</strong> (basada en feedback):</p><ul><li>Feedback de usuarios: quieren añadir etiquetas a tareas</li><li>Modificar PRD, añadir función de &quot;clasificación por etiquetas&quot;</li><li>Reejecutar la línea desde la etapa UI</li><li>Tiempo de entrega: medio día</li></ul><p><strong>Tercera ronda expansión</strong> (después de validación exitosa):</p><ul><li>Añadir función de gestión de miembros</li><li>Añadir recordatorios de fecha de vencimiento</li><li>Añadir función de comentarios en tareas</li><li>Tiempo de entrega: 2 días</li></ul><h4 id="checklist-de-verificacion-✅-1" tabindex="-1">Checklist de Verificación ✅ <a class="header-anchor" href="#checklist-de-verificacion-✅-1" aria-label="Permalink to &quot;Checklist de Verificación ✅&quot;">​</a></h4><p>Antes de cada iteración, verifica:</p><ul><li>[ ] La nueva función es consistente con el objetivo central</li><li>[ ] La nueva función tiene respaldo de demanda de usuarios</li><li>[ ] La nueva función aumentará significativamente la complejidad</li><li>[ ] Hay criterios de aceptación claros</li></ul><hr><h2 id="tecnicas-avanzadas" tabindex="-1">Técnicas Avanzadas <a class="header-anchor" href="#tecnicas-avanzadas" aria-label="Permalink to &quot;Técnicas Avanzadas&quot;">​</a></h2><h3 id="tecnica-5-utilizar-sesiones-separadas-para-ahorrar-tokens" tabindex="-1">Técnica 5: Utilizar Sesiones Separadas para Ahorrar Tokens <a class="header-anchor" href="#tecnica-5-utilizar-sesiones-separadas-para-ahorrar-tokens" aria-label="Permalink to &quot;Técnica 5: Utilizar Sesiones Separadas para Ahorrar Tokens&quot;">​</a></h3><h4 id="por-que-4" tabindex="-1">Por Qué <a class="header-anchor" href="#por-que-4" aria-label="Permalink to &quot;Por Qué&quot;">​</a></h4><p>Ejecutar la línea durante mucho tiempo provoca acumulación de contexto, consumiendo muchos tokens. <strong>Ejecución con sesiones separadas</strong> permite que cada etapa disfrute de un contexto limpio, reduciendo significativamente los costos de uso.</p><h4 id="como-hacerlo-4" tabindex="-1">Cómo Hacerlo <a class="header-anchor" href="#como-hacerlo-4" aria-label="Permalink to &quot;Cómo Hacerlo&quot;">​</a></h4><p><strong>En cada checkpoint, elige &quot;continuar en nueva sesión&quot;</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ejecutar en nueva ventana de línea de comandos</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p>El sistema automáticamente:</p><ol><li>Lee <code>.factory/state.json</code> para restaurar el estado</li><li>Inicia nueva ventana de Claude Code</li><li>Continúa desde la siguiente etapa pendiente de ejecución</li><li>Solo carga los archivos de entrada necesarios para esa etapa</li></ol><p><strong>Comparación</strong>:</p><table tabindex="0"><thead><tr><th>Método</th><th>Ventajas</th><th>Desventajas</th></tr></thead><tbody><tr><td>Continuar en misma sesión</td><td>Simple, no hay que cambiar ventana</td><td>Contexto acumulado, gran consumo de tokens</td></tr><tr><td>Continuar en nueva sesión</td><td>Cada etapa disfruta de contexto limpio, ahorra tokens</td><td>Necesita cambiar de ventana</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Práctica Recomendada</p><p><strong>Para proyectos grandes o con presupuesto de tokens limitado, se recomienda encarecidamente usar &quot;continuar en nueva sesión&quot;</strong>.</p><p>Para más detalles, consulta el tutorial <a href="./../../advanced/context-optimization/">Optimización de Contexto</a>.</p></div><hr><h3 id="tecnica-6-gestionar-fallos-y-reintentos" tabindex="-1">Técnica 6: Gestionar Fallos y Reintentos <a class="header-anchor" href="#tecnica-6-gestionar-fallos-y-reintentos" aria-label="Permalink to &quot;Técnica 6: Gestionar Fallos y Reintentos&quot;">​</a></h3><h4 id="por-que-5" tabindex="-1">Por Qué <a class="header-anchor" href="#por-que-5" aria-label="Permalink to &quot;Por Qué&quot;">​</a></h4><p>Durante la ejecución de la línea pueden encontrarse fallos (entrada insuficiente, problemas de permisos, errores de código, etc.). Entender cómo manejar fallos te permite recuperar el progreso más rápidamente.</p><h4 id="como-hacerlo-5" tabindex="-1">Cómo Hacerlo <a class="header-anchor" href="#como-hacerlo-5" aria-label="Permalink to &quot;Cómo Hacerlo&quot;">​</a></h4><p><strong>Mejores prácticas de manejo de fallos</strong> (referencia <code>failure.policy.md:267-274</code>):</p><ol><li><strong>Fallo temprano</strong>: detectar problemas temprano para evitar desperdiciar tiempo en etapas posteriores</li><li><strong>Registros detallados</strong>: registrar suficiente información de contexto para facilitar la resolución de problemas</li><li><strong>Operaciones atómicas</strong>: la salida de cada etapa debe ser atómica para facilitar revertir</li><li><strong>Conservar evidencia</strong>: archivar productos fallidos antes de reintentar para facilitar análisis comparativos</li><li><strong>Reintento gradual</strong>: proporcionar orientación más específica al reintentar, no simplemente repetir</li></ol><p><strong>Escenarios comunes de fallos</strong>:</p><table tabindex="0"><thead><tr><th>Tipo de Fallo</th><th>Síntoma</th><th>Solución</th></tr></thead><tbody><tr><td>Salida faltante</td><td><code>input/idea.md</code> no existe</td><td>Reintentar, verificar ruta de escritura</td></tr><tr><td>Expansión de alcance</td><td>Cantidad de funciones &gt; 7</td><td>Reintentar, pedir simplificar a MVP</td></tr><tr><td>Error técnico</td><td>Fallo de compilación TypeScript</td><td>Verificar definiciones de tipos, reintentar</td></tr><tr><td>Problema de permisos</td><td>Agent escribe en directorio no autorizado</td><td>Verificar matriz de límites de capacidades</td></tr></tbody></table><p><strong>Checklist de recuperación de fallos</strong>:</p><ul><li>[ ] La causa del fallo está clara</li><li>[ ] La solución de reparación se ha implementado</li><li>[ ] La configuración relacionada se ha actualizado</li><li>[ ] Reanudar desde la etapa donde falló</li></ul><div class="tip custom-block"><p class="custom-block-title">Los Fallos son Normales</p><p><strong>¡No tengas miedo de los fallos!</strong> AI App Factory tiene diseñados mecanismos completos de manejo de fallos:</p><ul><li>Cada etapa permite un reintento automático</li><li>Los productos fallidos se archivan automáticamente en <code>artifacts/_failed/</code></li><li>Puede revertir al último checkpoint exitoso</li></ul><p>Cuando encuentres un fallo, analiza la causa con calma y procesa según la estrategia de fallo.</p></div><hr><h2 id="resumen-del-curso" tabindex="-1">Resumen del Curso <a class="header-anchor" href="#resumen-del-curso" aria-label="Permalink to &quot;Resumen del Curso&quot;">​</a></h2><p>Este curso presentó las seis mejores prácticas de AI App Factory:</p><ol><li><strong>Descripciones claras del producto</strong>: describir en detalle usuarios objetivo, problema central, funciones clave y condiciones de restricción</li><li><strong>Confirmar cuidadosamente en checkpoints</strong>: verificar la calidad de salida después de cada etapa para evitar la acumulación de errores</li><li><strong>Utilizar objetivos negativos para controlar el alcance</strong>: enumerar claramente las funciones que no se harán para evitar la expansión del alcance</li><li><strong>Iterar gradualmente</strong>: validar primero la idea central y luego expandir gradualmente basándose en el feedback de usuarios</li><li><strong>Sesiones separadas para ahorrar tokens</strong>: crear nueva sesión en cada checkpoint para reducir los costos de uso</li><li><strong>Manejar correctamente los fallos</strong>: utilizar los mecanismos de manejo de fallos para recuperar el progreso rápidamente</li></ol><p>Seguir estas mejores prácticas hará que tu experiencia con AI App Factory sea más fluida, que la calidad de las aplicaciones generadas sea mayor y que tu eficiencia de desarrollo se multiplique por varias veces.</p><hr><h2 id="proximo-curso" tabindex="-1">Próximo Curso <a class="header-anchor" href="#proximo-curso" aria-label="Permalink to &quot;Próximo Curso&quot;">​</a></h2><blockquote><p>En el próximo curso aprenderemos la <strong><a href="./../../appendix/cli-commands/">Referencia de Comandos CLI</a></strong>.</p><p>Aprenderás:</p><ul><li>Todos los parámetros y opciones del comando factory init</li><li>Cómo el comando factory run comienza desde una etapa específica</li><li>Cómo el comando factory continue continúa en nueva sesión</li><li>Cómo factory status y factory list muestran información del proyecto</li><li>Cómo factory reset restablece el estado del proyecto</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del Código Fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver ubicaciones del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del Archivo</th><th>Número de Líneas</th></tr></thead><tbody><tr><td>Técnicas de descripción del producto</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L186-L210" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>186-210</td></tr><tr><td>Mecanismo de checkpoints</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md#L98-L112" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>98-112</td></tr><tr><td>Control de objetivos negativos</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L199-L203" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>199-203</td></tr><tr><td>Estrategia de manejo de fallos</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md#L267-L274" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>267-274</td></tr><tr><td>Aislamiento de contexto</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md#L10-L42" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>10-42</td></tr><tr><td>Estándares de código</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>Todo el documento</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>MAX_RETRY_COUNT = 1</code>: cada etapa permite un reintento automático por defecto</li></ul><p><strong>Reglas clave</strong>:</p><ul><li>Cantidad de funciones Must Have ≤ 7 (principio MVP)</li><li>Cantidad de páginas ≤ 3 (etapa UI)</li><li>Cantidad de modelos de datos ≤ 10 (etapa Tech)</li><li>Cobertura de pruebas &gt; 60% (etapa Validation)</li></ul></details>`,131)])])}const h=a(t,[["render",s]]);export{m as __pageData,h as default};
